module top_module(obf_a, b, ctrl, result);input [3:0] obf_a, b;
    input [1:0] ctrl;
    output reg [3:0] result;

    always @(*) begin
        case(ctrl)
            2'b00: result = obf_a + b;
            2'b01: result = obf_a - b;
            2'b10: result = obf_a & b;
            2'b11: result = obf_a | b;
        endcase
    end
endmodule
